#include <stdio.h>
#include <stdlib.h>

// Structure to represent a square
typedef struct Square {
    int x, y, a;
    int id;
} Square;

// Function to compare two squares
int compareSquares(const void *a, const void *b) {
    Square *s1 = (Square *)a;
    Square *s2 = (Square *)b;
    if (s1->x != s2->x) return s1->x - s2->x;
    if (s1->y != s2->y) return s1->y - s2->y;
    return s1->a - s2->a;
}

// Function to check if a square is inside another square
int isInside(Square *s1, Square *s2) {
    return s1->x >= s2->x && s1->y >= s2->y && s1->x + s1->a <= s2->x + s2->a && s1->y + s1->a <= s2->y + s2->a;
}

// Function to find the winner of the game
int findWinner(Square *squares, int n) {
    // Create a graph where each square is a node, and two nodes are connected if one square is inside the other
    int **graph = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        graph[i] = (int *)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            graph[i][j] = 0;
        }
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i != j && isInside(&squares[i], &squares[j])) {
                graph[i][j] = 1;
            }
        }
    }

    // Perform a depth-first search to find the winner of the game
    int *visited = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        visited[i] = 0;
    }
    int winner = -1;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            int result = dfs(graph, visited, squares, i, n);
            if (result == 1) {
                winner = squares[i].id;
                break;
            }
        }
    }
    free(visited);
    for (int i = 0; i < n; i++) {
        free(graph[i]);
    }
    free(graph);
    return winner;
}

// Function to perform a depth-first search
int dfs(int **graph, int *visited, Square *squares, int node, int n) {
    visited[node] = 1;
    int result = 0;
    for (int i = 0; i < n; i++) {
        if (graph[node][i] && !visited[i]) {
            result = dfs(graph, visited, squares, i, n);
            if (result == 0) {
                return 1;
            }
        }
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n;
        scanf("%d", &n);
        Square *squares = (Square *)malloc(n * sizeof(Square));
        for (int i = 0; i < n; i++) {
