    }

    // Function to find the winner of the game
    public static int findWinner(Square[] squares) {
        // Create a graph where each square is a node, and two nodes are connected if one square is inside the other
        int[][] graph = new int[squares.length][squares.length];
        for (int i = 0; i < squares.length; i++) {
            for (int j = 0; j < squares.length; j++) {
                if (i != j && isInside(squares[i], squares[j])) {
                    graph[i][j] = 1;
                }
            }
        }

        // Perform a depth-first search to find the winner of the game
        int[] visited = new int[squares.length];
        int winner = -1;
        for (int i = 0; i < squares.length; i++) {
            if (visited[i] == 0) {
                int result = dfs(graph, visited, squares, i);
                if (result == 1) {
                    winner = squares[i].id;
                    break;
                }
            }
        }
        return winner;
    }

    // Function to perform a depth-first search
    public static int dfs(int[][] graph, int[] visited, Square[] squares, int node) {
        visited[node] = 1;
        int result = 0;
        for (int i = 0; i < squares.length; i++) {
            if (graph[node][i] == 1 && visited[i] == 0) {
                result = dfs(graph, visited, squares, i);
                if (result == 0) {
                    return 1;
                }
            }
        }
        return result;
    }

